import numpy as npimport matplotlib.pyplot as pltimport pandas as pd# Load datasetdataset = pd.read_csv(r"/Users/afsarazam/Desktop/ML tools& tech/Social_Network_Ads.csv")# Features (X) and Target (y)x = dataset.iloc[:, :-1].valuesy = dataset.iloc[:, -1].values  # Split datasetfrom sklearn.model_selection import train_test_splitx_train, x_test, y_train, y_test = train_test_split(x, y, test_size=0.15, random_state=0)# Feature Scalingfrom sklearn.preprocessing import StandardScalersc = StandardScaler()x_train = sc.fit_transform(x_train)x_test = sc.transform(x_test)# Decision Tree Modelfrom sklearn.tree import DecisionTreeClassifierclassifier = DecisionTreeClassifier(    criterion='gini',    splitter='random',           max_depth=10,    random_state=0)classifier.fit(x_train, y_train)y_pred = classifier.predict(x_test)from sklearn.metrics import confusion_matrix, accuracy_scorecm = confusion_matrix(y_test, y_pred)ac = accuracy_score(y_test, y_pred)print("Confusion Matrix:\n", cm)print("Accuracy:", ac)